import DataService from "../../../services/DataService";

let leftsearchSchema = [
   
    {
        fieldName: 'State',
        fieldType: "ddl-radio",
        fieldIcon: "fa fa-map-marker",
        paramName: "State",
        fieldSearchConditionName: [''],
        isSearch: false,
        value: "",
        listOptions: []
    },

    {
        fieldName: 'UtilityName',
        fieldType: "ddl-radio",
        fieldIcon: "fa fa-map-marker",
        paramName: "UtilityName",
        fieldSearchConditionName: [''],
        isSearch: false,
        value: "",
        listOptions: []
    },

    {
        fieldName: 'Workcode',
        fieldType: "ddl-radio",
        fieldIcon: "fa fa-map-marker",
        paramName: "Workcode",
        fieldSearchConditionName: [''],
        isSearch: false,
        value: "",
        listOptions: []
    },
   
];


async function bindleftCommonSearchdropdown(instance) {
    var vm = instance;

    try {
        /* ================= STATE LIST ================= */
        const stateUrl = `countryId=223&includeCandaState=true`;
        const stateResponse = await DataService.GetStateList(stateUrl);

        if (stateResponse.data) {
            const stateOptions = stateResponse.data.map(item => ({
                name: item.stateName,
                value: item.stateId
            }));

            const stateField = vm.leftSearchFields.find(
                f => f.fieldName === 'State'
            );

            if (stateField) {
                stateField.listOptions = stateOptions;
            }
        }

        /* ================= UTILITY LIST ================= */
        const utilityUrl = `clientId=531039&configId=&reqFrom=&clientIds=`;
        const utilityResponse = await DataService.getUtilityList(utilityUrl);

        if (utilityResponse.data) {
            const utilityOptions = utilityResponse.data.map(item => ({
                name: item.UTILITY_NAME,
                value: item.UTILITY_ID
            }));

            const utilityField = vm.leftSearchFields.find(
                f => f.fieldName === 'UtilityName'
            );

            if (utilityField) {
                utilityField.listOptions = utilityOptions;
            }
        }

        /* ================= WORK CODE LIST ================= */
        const workCodeResponse = await DataService.GetWorkCodeData();

        if (workCodeResponse.data) {
            const workCodeOptions = workCodeResponse.data.map(item => ({
                name: item.WORK_CODE_NAME || item.text || item.name,
                value: item.WORK_CODE_ID || item.value
            }));

            const workCodeField = vm.leftSearchFields.find(
                f => f.fieldName === 'Workcode'
            );

            if (workCodeField) {
                workCodeField.listOptions = workCodeOptions;
            }
        }

    } catch (error) {
        console.error('Error loading State / Utility / WorkCode:', error);
    }
}


export default { leftsearchSchema ,bindleftCommonSearchdropdown};